\begin{corollary}\leanok
[Defining property of the Hilbert polynomial]
  \label{cor:hilbertPolynomial_eval_eventually}
  \lean{AlgebraicGeometry.Scheme.hilbertPolynomial_eval_eventually}
  \uses{def:hilbert_polynomial, def:fiber_hilbert_function,
    lem:hilbertPolynomial_unique}
  % ENCODING. Scheme.hilbertPolynomial_eval_eventually. Sorry-free in
  % AlgebraicJacobian/Picard/HilbertPolynomial.lean.
  Let \(h_{\mathcal{F},s}\) be the graded Hilbert function of
  \cref{def:fiber_hilbert_function}. If \emph{some} polynomial in
  \(\mathbb{Q}[\lambda]\) agrees with \(h_{\mathcal{F},s}\) at all
  sufficiently large integers, then the Hilbert polynomial
  \(\Phi_{\mathcal{F},s}\) of \cref{def:hilbert_polynomial} does:
  \(\Phi_{\mathcal{F},s}(m) = h_{\mathcal{F},s}(m)\) for all \(m \gg 0\).
\end{corollary}

\begin{proof}
  \uses{def:hilbert_polynomial, lem:hilbertPolynomial_unique}
  \leanok
  Let \(\Psi \in \mathbb{Q}[\lambda]\) agree with \(h_{\mathcal{F},s}\) at all
  \(m > N\). By \cref{def:hilbert_polynomial} the Hilbert polynomial
  \(\Phi_{\mathcal{F},s}\) is a polynomial agreeing with
  \(h_{\mathcal{F},s}\) for all \(m \gg 0\) whenever one exists, and by
  \cref{lem:hilbertPolynomial_unique} any such polynomial is unique, so
  \(\Phi_{\mathcal{F},s} = \Psi\); hence
  \(\Phi_{\mathcal{F},s}(m) = h_{\mathcal{F},s}(m)\) for all \(m > N\).
\end{proof}

